// // This module implements a 1-bit DRAM cell with write enable functionality.
// It stores a single bit of data and updates it only when the write enable signal is high.
// The output reflects the last written value or remains unchanged if no write occurs.
module dram_cell (
    input wire d,
    input wire we,
    input wire clk,
    output reg q
);
    reg stored_bit;

    always @(posedge clk) begin
        if (we) begin
            stored_bit <= d;
        end
    end

    always @* begin
        q = stored_bit;
    end
endmodule

